mapper.select:
select t1.id, t1.job_name, t1.job_type, t1.job_group, t1.execution_time, t1.start_time, t1.end_time, t1.status from sys_schedule_record t1 where t1.del_flag = '0' and t1.job_id = #{jobId}
and (t1.job_name like #{keyword} or t1.job_group like #{keywordPattern})
and t1.start_time between #{startTime} and #{endTime}
order by t1.create_time desc
